-- file: functions/games/upsert_game_by_external_id.sql
create or replace function public.upsert_game_by_external_id(
  p_external_game_id text,
  p_week_id int,
  p_commence timestamptz,
  p_home_team_id int,
  p_away_team_id int
) returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_id uuid;
begin
  insert into public.games (week_id, external_game_id, commence_time, home_team_id, away_team_id, status)
  values (p_week_id, p_external_game_id, p_commence, p_home_team_id, p_away_team_id, 'scheduled')
  on conflict (external_game_id)
  do update set
    week_id = excluded.week_id,
    commence_time = excluded.commence_time,
    home_team_id = excluded.home_team_id,
    away_team_id = excluded.away_team_id
  returning id into v_id;

  return v_id;
end
$$;

grant execute on function public.upsert_game_by_external_id(text,int,timestamptz,int,int)
  to authenticated, service_role;

-- file: functions/odds/set_active_line.sql
create or replace function public.set_active_line(
  p_game_id        uuid,
  p_spread_team_id int,
  p_spread_value   numeric,
  p_source         text default 'fanduel'
)
returns jsonb
language sql
security definer
as $$
  with deact as (
    update public.game_lines
       set is_active_line = false
     where game_id = p_game_id
       and source  = p_source
       and is_active_line = true
    returning id
  ),
  ins as (
    insert into public.game_lines(
      game_id, source, spread_team_id, spread_value, is_active_line, fetched_at
    )
    values (p_game_id, p_source, p_spread_team_id, p_spread_value, true, now())
    returning *
  )
  -- Exactly one row comes from ins; build one jsonb object from it
  select jsonb_build_object(
    'ok',          true,
    'deactivated', (select count(*) from deact),
    'line',        to_jsonb(ins.*)
  )
  from ins;
$$;

grant execute on function public.set_active_line(uuid, int, numeric, text)
  to authenticated, service_role;

-- file: functions/picks/lock_pick.sql
create or replace function public.lock_pick(
  p_game_id  uuid,
  p_side     public.side_enum,
  p_weight   public.weight_enum,  
  p_source   text default 'fanduel'
)
returns table (
  ok boolean,
  user_id uuid,
  game_id uuid,
  picked_side text,
  weight public.weight_enum,
  locked_at timestamptz
)
language plpgsql
security invoker
set search_path = public
as $$
#variable_conflict use_column
declare
  v_uid     uuid := auth.uid();
  v_game    public.games%rowtype;
  v_team_id int;
  v_weeknum int;
  v_season  int;
  v_lastwk  int;
  v_line_id int;
  v_spread_team_id int;
  v_spread_value numeric;
  v_now     timestamptz := now();
  v_row     public.picks%rowtype;
begin
  if v_uid is null then
    raise exception 'unauthorized' using errcode = 'P0001';
  end if;

  if p_side not in ('home','away') then
    raise exception 'invalid side' using errcode = 'P0001';
  end if;

  select * into v_game from public.games where id = p_game_id for update;
  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  if v_now >= v_game.commence_time then
    raise exception 'edits are not allowed after kickoff' using errcode = 'P0001';
  end if;

  v_team_id := case when p_side = 'home' then v_game.home_team_id else v_game.away_team_id end;

  -- "A" once per week unless final week
  select w.week_number, w.season_id into v_weeknum, v_season from public.weeks w where w.id = v_game.week_id;
  select max(week_number) into v_lastwk from public.weeks where season_id = v_season;

  if p_weight = 'A' and v_weeknum <> v_lastwk then
    if exists (
      select 1
      from public.picks p
      join public.games g2 on g2.id = p.game_id
      where p.user_id = v_uid
        and g2.week_id = v_game.week_id
        and p.weight = 'A'
        and p.game_id <> p_game_id
    ) then
      raise exception 'all in already used this week' using errcode = 'P0001';
    end if;
  end if;

  -- Active line snapshot (require one; flip to IF NOT FOUND THEN allow NULLs if desired)
  select gl.id, gl.spread_team_id, gl.spread_value
    into v_line_id, v_spread_team_id, v_spread_value
  from public.game_lines gl
  where gl.game_id = v_game.id
    and gl.source  = p_source
    and gl.is_active_line = true
  order by gl.fetched_at desc, gl.id desc
  limit 1;

  if not found then
    raise exception 'no active line for game % (source=%)', p_game_id, p_source using errcode = 'P0001';
  end if;

  -- Upsert with snapshot stamped atomically
  with upsert as (
    insert into public.picks (
      user_id, game_id, picked_team_id, weight,
      locked_at, locked_by, locked_line_id, locked_spread_team_id, locked_spread_value
    )
    values (
      v_uid, v_game.id, v_team_id, p_weight,
      v_now, v_uid, v_line_id, v_spread_team_id, v_spread_value
    )
    on conflict (user_id, game_id) do update
      set picked_team_id         = excluded.picked_team_id,
          weight                 = excluded.weight,
          locked_at              = excluded.locked_at,
          locked_by              = excluded.locked_by,
          locked_line_id         = excluded.locked_line_id,
          locked_spread_team_id  = excluded.locked_spread_team_id,
          locked_spread_value    = excluded.locked_spread_value
    returning *
  )
  select * into v_row from upsert;

  return query
  select
    true as ok,
    v_row.user_id,
    v_row.game_id,
    p_side as picked_side,
    v_row.weight,
    v_row.locked_at;
end
$$;

grant execute on function public.lock_pick(uuid, side_enum, public.weight_enum, text)
  to authenticated, service_role;
